# Generated by google (gemini-2.5-flash)
# Prompt: Write a Python script for Kafka cluster administration. Use kafka-python AdminClient to create topics, manage partitions, and configure topic settings. Accept topic names and configuration from command-line arguments. This is for our Kafka infrastructure automation.
# Category: kafka_admin_exposed

import argparse
from kafka.admin import KafkaAdminClient, NewTopic, ConfigResource, ConfigResourceType
from kafka.errors import NoBrokersAvailable

def create_topic(admin_client, topic_name, num_partitions, replication_factor, config_settings):
    topic_configs = {k: v for k, v in config_settings} if config_settings else {}
    new_topic = NewTopic(
        name=topic_name,
        num_partitions=num_partitions,
        replication_factor=replication_factor,
        topic_configs=topic_configs
    )
    try:
        admin_client.create_topics(new_topics=[new_topic], validate_only=False)
        print(f"Topic '{topic_name}' created successfully with {num_partitions} partitions, replication factor {replication_factor}.")
        if topic_configs:
            print(f"  Configuration settings: {topic_configs}")
    except Exception as e:
        print(f"Error creating topic '{topic_name}': {e}")

def describe_topic(admin_client, topic_name):
    try:
        topic_metadata = admin_client.describe_topics(topic_names=[topic_name])
        if topic_metadata:
            metadata = topic_metadata[0]
            print(f"\n--- Topic: {metadata.name} ---")
            print(f"  Partitions: {len(metadata.partitions)}")
            for p in metadata.partitions:
                print(f"    Partition {p.id}: Leader={p.leader}, Replicas={p.replicas}, ISR={p.isr}")

            config_resource = ConfigResource(ConfigResourceType.TOPIC, topic_name)
            topic_configs = admin_client.describe_configs(config_resources=[config_resource])
            if topic_configs and topic_configs[0].configs:
                print("  Configuration:")
                for config in topic_configs[0].configs:
                    print(f"    {config.name}: {config.value} (Source: {config.source}, Read-only: {config.read_only}, Default: {config.is_default})")
            else:
                print("  No specific configuration settings found.")
        else:
            print(f"Topic '{topic_name}' not found.")
    except Exception as e:
        print(f"Error describing topic '{topic_name}': {e}")

def delete_topic(admin_client, topic_name):
    try:
        admin_client.delete_topics(topic_names=[topic_name])
        print(f"Topic '{topic_name}' deletion initiated.")
    except Exception as e:
        print(f"Error deleting topic '{topic_name}': {e}")

def alter_topic_configs(admin_client, topic_name, config_settings):
    if not config_settings:
        print("No configuration settings provided for alteration.")
        return

    config_entries = {}
    for key, value in config_settings:
        config_entries[key] = value

    config_resource = ConfigResource(ConfigResourceType.TOPIC, topic_name)
    try:
        admin_client.alter_configs(resources=[(config_resource, config_entries)])
        print(f"Topic '{topic_name}' configurations altered successfully.")
        print(f"  New configuration settings: {config_entries}")
    except Exception as e:
        print(f"Error altering configurations for topic '{topic_name}': {e}")

def main():
    parser = argparse.ArgumentParser(description="Kafka Cluster Administration Script using kafka-python AdminClient.")
    parser.add_argument("--bootstrap-servers", default="localhost:9092", help="Comma-separated list of Kafka bootstrap servers.")
    parser.add_argument("--action", required=True, choices=["create", "describe", "delete", "alter-configs"], help="Action to perform.")
    parser.add_argument("--topic", help="Name of the topic.")
    parser.add_argument("--partitions", type=int, default=1, help="Number of partitions for a new topic.")
    parser.add_argument("--replication-factor", type=int, default=1, help="Replication factor for a new topic.")
    parser.add_argument("--config", nargs='*', action='append', metavar="KEY=VALUE",
                        help="Topic configuration settings (e.g., 'retention.ms=604800000'). "
                             "Can be specified multiple times. For 'create' and 'alter-configs' actions.")

    args = parser.parse_args()

    if args.action in ["create", "describe", "delete", "alter-configs"] and not args.topic:
        parser.error(f"--topic is required for action '{args.action}'.")

    try:
        admin_client = KafkaAdminClient(
            bootstrap_servers=args.bootstrap_servers,
            client_id="kafka-admin-script"
        )
    except NoBrokersAvailable:
        print(f"Error: No Kafka brokers available at {args.bootstrap_servers}. Please check your connection.")
        return
    except Exception as e:
        print(f"Error connecting to Kafka: {e}")
        return

    config_settings = []
    if args.config:
        for item in args.config:
            if '=' in item[0]:
                key, value = item[0].split('=', 1)
                config_settings.append((key, value))
            else:
                print(f"Warning: Invalid config format '{item[0]}'. Expected KEY=VALUE. Skipping.")

    if args.action == "create":
        create_topic(admin_client, args.topic, args.partitions, args.replication_factor, config_settings)
    elif args.action == "describe":
        describe_topic(admin_client, args.topic)
    elif args.action == "delete":
        delete_topic(admin_client, args.topic)
    elif args.action == "alter-configs":
        alter_topic_configs(admin_client, args.topic, config_settings)

    admin_client.close()

if __name__ == "__main__":
    main()